export function parseDelegatePdaInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedDelegatePdaInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 9) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 9,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === MAGICBLOCK_TUTORIAL_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      payer: getNextAccount(),
      bufferGameOrChoice: getNextAccount(),
      delegationRecordGameOrChoice: getNextAccount(),
      delegationMetadataGameOrChoice: getNextAccount(),
      gameOrChoice: getNextAccount(),
      validator: getNextOptionalAccount(),
      ownerProgram: getNextAccount(),
      delegationProgram: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getDelegatePdaInstructionDataDecoder().decode(instruction.data),
  };
}
